class DropBoxController {

  constructor() {

    this.onselectionchange = new Event('selectionchange');
    this.currentFolder = ['HiperCloud'];
    this.navEl = document.querySelector('#browse-location');
    this.btnSendFileEl = document.querySelector("#btn-send-file");
    this.inputFilesEl = document.querySelector("#files");
    this.snackModalEl = document.querySelector("#react-snackbar-root");
    this.progressBarEl = this.snackModalEl.querySelector('.mc-progress-bar-fg')
    this.nameFileEl = this.snackModalEl.querySelector('.filename')
    this.timeleftEl = this.snackModalEl.querySelector('.timeleft')
    this.listFilesEl = document.querySelector('#list-of-files-and-directories')    
    this.btnNewFolder = document.querySelector('#btn-new-folder')
    this.btnRename = document.querySelector('#btn-rename')
    this.btnDelete = document.querySelector('#btn-delete')
    this.connDatabase();
    this.initEvents();
    this.openFolder();   

  }

  connDatabase() {

    const firebaseConfig = {
      /* Here you enter your firebase configuration */
    };

    // Initialize Firebase
    firebase.initializeApp(firebaseConfig);    

  }

  getSelection() {

    return this.listFilesEl.querySelectorAll('.selected');

  }

  removeFolder(ref, name) {

    return new Promise((resolve, reject) => {

      let folderRef = this.getFirebaseRef(ref + '/' + name);

      folderRef.on('value', snapshot => {

        folderRef.off('value');

        snapshot.forEach(item => {

          let data = item.val();
          data.key = item.key;

          if (data.type === 'folder') {

            this.removeFolder(ref + '/' + name, data.name).then(() => {

              resolve({
                fields: {
                  key: data.key
                }
              });

            }).catch(err => {
              reject(err);
            });

          } else if (data.type) {

            this.removeFile(ref + '/' + name, data.name).then(() => {

              resolve({
                fields: {
                  key: data.key
                }
              });

            }).catch(err => {
              reject(err);
            });

          }

        });

        folderRef.remove();       

      });

    });

  }

  removeTask() {

    let promises = [];

    this.getSelection().forEach(li=>{

      let file = JSON.parse(li.dataset.file);
      let key = li.dataset.key;

      promises.push(new Promise((resolve, reject) => {

        if (file.type === 'folder') {

          this.removeFolder(this.currentFolder.join('/'), file.name).then(()=>{

            resolve({
              fields: {
                key
              }
            });

          });

        } else if (file.type) {

          this.removeFile(this.currentFolder.join('/'), file.name).then(()=>{

            resolve({
              fields: {
                key
              }
            });

          });      

        }       

      }));

      // let formData = new FormData();
      // formData.append('path', file.path);
      // formData.append('key', key);
      //promises.push(this.ajax('/file', 'DELETE', formData));      

    });

    return Promise.all(promises);

  }

  removeFile(ref, name) {

    let fileRef = firebase.storage().ref(ref).child(name);

    return fileRef.delete();

  }

  initEvents() {

    this.btnNewFolder.addEventListener('click', e=>{

      let name = prompt('Nome da nova pasta: ');

      if (name) {

        this.getFirebaseRef().push().set({

          name,
          type: 'folder',
          path: this.currentFolder.join('/')

        });

      }

    });

    this.btnDelete.addEventListener('click', e=>{

      this.removeTask().then(responses=>{

        responses.forEach(response => {

          if (response.fields.key) {

            this.getFirebaseRef().child(response.fields.key).remove();

          }

        });

      }).catch(err => {

        console.error(err);

      });

    });

    this.btnRename.addEventListener('click', e=>{

      let li = this.getSelection()[0];
      let file = JSON.parse(li.dataset.file)
      let name = prompt("Renomear o arquivo: ", file.name);

      if (name) {

        file.name = name;

        this.getFirebaseRef().child(li.dataset.key).set(file);

      }

    });

    this.listFilesEl.addEventListener('selectionchange', e => {

      switch (this.getSelection().length) {

        case 0:
          this.btnDelete.style.display = 'none';
          this.btnRename.style.display = 'none';
        break;

        case 1:
          this.btnDelete.style.display = 'block';
          this.btnRename.style.display = 'block';
        break;

        default:
          this.btnDelete.style.display = 'block';
          this.btnRename.style.display = 'none';

      }

    });

    this.btnSendFileEl.addEventListener("click", event => {

      this.inputFilesEl.click();

    });

    this.inputFilesEl.addEventListener("change", event => {

      this.btnSendFileEl.disabled = true;     

      this.uploadTask(event.target.files).then(responses => {

        responses.forEach(resp => {

          this.getFirebaseRef().push().set({

            name: resp.name,
            type: resp.contentType,     
            path: resp.customMetadata.downloadURL,
            size: resp.size       

          });

        });   

        this.uploadComplete();

      }).catch(err => {

        this.uploadComplete();
        console.error(err);

      });  

      this.modalShow();  


    });

  }

  uploadComplete() {

    this.modalShow(false); 
    this.inputFilesEl.value = ""; 
    this.btnSendFileEl.disabled = false;

  }

  getFirebaseRef(path) {

    if (!path) path = this.currentFolder.join('/');

    return firebase.database().ref(path);

  }

  modalShow(show = true) {

    this.snackModalEl.style.display = (show) ? "block" : "none";

  }

  ajax(url, method = 'GET', formData = new FormData(), onprogress = function(){}, onloadstart = function(){}) {

    return new Promise((resolve, reject) => {

      let ajax = new XMLHttpRequest();  
      ajax.open(method, url);  
      ajax.onload = event => {

        try {
            resolve(JSON.parse(ajax.responseText));
        } catch (e) {
            reject(e);
        }

      }

      ajax.onerror = event => {

        reject(event);

      }

      ajax.upload.onprogress = onprogress;
      onloadstart();
      ajax.send(formData);

    });    

  }

  uploadTask(files) {

    let promises = [];

    [...files].forEach(file => {        

      promises.push(new Promise ((resolve, reject) => {

        let fileRef = firebase.storage().ref(this.currentFolder.join('/')).child(file.name);

        let task = fileRef.put(file);

        task.on('state_changed', snapshot=>{

          this.uploadProgress({
            loaded: snapshot.bytesTransferred,
            total: snapshot.totalBytes
          }, file);

        }, error => {

          console.error(error);
          reject(error);

        }, () => {

          task.snapshot.ref.getDownloadURL().then(downloadURL => {

            task.snapshot.ref.updateMetadata({ customMetadata: {downloadURL} }).then(metadata => {

              resolve(metadata);

            });

          }).catch(error => {

            console.error(error);
            reject(error);

          });

        });

      }));

    });

    return Promise.all(promises);

  }

  uploadProgress(event, file) {

    let timespent = Date.now() - this.startUploadTime;
    let loaded = event.loaded;
    let total = event.total;
    let porcent = parseInt((loaded / total) * 100);   
    let timeleft = ((100 - porcent) * timespent) / porcent;  
    this.progressBarEl.style.width = `${porcent}%`;  
    this.nameFileEl.innerHTML = file.name;      
    this.timeleftEl.innerHTML = this.formatTimeToHuman(timeleft); 

  }

  formatTimeToHuman(duration) {

    let seconds = parseInt((duration / 1000) % 60);
    let minutes = parseInt((duration / (1000 * 60)) % 60);
    let hours = parseInt((duration / (1000 * 60 * 60)) % 24);

    if (hours > 0) {
      return `${hours} horas, ${minutes} minutos e ${seconds} segundos`;
    }

    if (minutes > 0) {
      return `${minutes} minutos e ${seconds} segundos`;
    }

    if (seconds > 0) {
      return `${seconds} segundos`;
    }

    return '';

  }

